// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.leo;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertSame;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.BindingMask;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.BindingUniverse;
import org.junit.jupiter.api.Test;

class LeoEvidenceTest {

	@Test
	void protectedExactEvidenceWinsOverLearnedAndSamplingEvidence() {
		LeoEvidence exact = LeoEvidence.exactFiniteRelation(2.0d, 2.0d, "exact-values");
		LeoEvidence learned = LeoEvidence.persistedFanoutHistogram(100_000.0d, 110_000.0d, 0.99d, 40L,
				"persisted-heavy-hitter");
		LeoEvidence sampled = LeoEvidence.sampling(80_000.0d, 90_000.0d, 0.90d, 4L, "raw-sample");

		assertSame(exact, LeoEvidence.bestOf(List.of(sampled, learned, exact)).orElseThrow());
		assertTrue(exact.protectedEstimate());
	}

	@Test
	void evidencePriorityPrefersQueryLocalSketchOverScalarCorrection() {
		LeoEvidence scalar = LeoEvidence.scalarCorrection(50.0d, 60.0d, 0.95d, 12L, "operator-feedback");
		LeoEvidence virtualSketch = LeoEvidence.queryLocalVirtualSketch(400.0d, 430.0d, 0.75d, 1L,
				"finite-anchor-virtual-sketch");

		assertSame(virtualSketch, LeoEvidence.bestOf(List.of(scalar, virtualSketch)).orElseThrow());
	}

	@Test
	void scalarCorrectionBeatsBaseStatisticsButNotProtectedEvidence() {
		LeoEvidence scalar = LeoEvidence.scalarCorrection(10_000.0d, 12_000.0d, 0.80d, 6L,
				"operator-feedback");
		LeoEvidence base = LeoEvidence.baseStats(100.0d, 150.0d, 0.95d, 1L, "base-stats");

		assertSame(scalar, LeoEvidence.bestOf(List.of(base, scalar)).orElseThrow(),
				"LEO feedback must be able to repair stale base statistics once it is trusted");
	}

	@Test
	void memoFeedbackKeepsBestEvidenceAndRuleHints() {
		LeoEvidence scalar = LeoEvidence.scalarCorrection(10.0d, 12.0d, 0.70d, 2L, "scalar");
		LeoEvidence finite = LeoEvidence.exactFiniteRelation(7.0d, 8.0d, "finite");
		LeoRuleHint hint = LeoRuleHint.of("lmdb-materialized-minus-anti-semi", 50,
				"correlated-minus high q-error", 0.80d);

		LeoMemoFeedback feedback = LeoMemoFeedback.of(List.of(scalar, finite), List.of(hint));

		assertSame(finite, feedback.bestEvidence().orElseThrow());
		assertEquals(50, feedback.priorityDelta("lmdb-materialized-minus-anti-semi"));
		assertEquals(0, feedback.priorityDelta("generic-physical-implementation"));
	}

	@Test
	void surfaceKeyUsesBindingMasksAndCardinalityBuckets() {
		BindingUniverse universe = BindingUniverse.create();
		BindingMask left = universe.maskOf(Set.of("branchName"));
		BindingMask right = universe.maskOf(Set.of("branch", "copy"));
		BindingMask shared = universe.maskOf(Set.of("branch"));
		BindingMask output = left.union(right);

		LeoSurfaceKey key = new LeoSurfaceKey("join", output, left, right, shared,
				"pos", "urn:locatedAt", "bound-lookup",
				LeoSurfaceKey.cardinalityBucket(386_000.0d), LeoSurfaceKey.cardinalityBucket(42.0d));

		assertEquals("join", key.operatorKind());
		assertEquals(output, key.outputMask());
		assertEquals(shared, key.sharedMask());
		assertEquals(LeoSurfaceKey.cardinalityBucket(386_000.0d), key.inputCardinalityBucket());
		assertEquals(LeoSurfaceKey.cardinalityBucket(42.0d), key.outputCardinalityBucket());
	}
}
